"use client";
import { useState } from "react";
import { motion, useReducedMotion } from "framer-motion";
export default function IntervalNudgeField(){const [value,setValue]=useState(25);const reduced=useReducedMotion();const change=(next:number)=>setValue(Math.max(15,Math.min(90,next)));return <section className="w-full max-w-sm rounded-[22px] border border-[#ececee] bg-white p-5 shadow-sm"><label htmlFor="interval" className="text-sm font-black text-[#111]">Focus interval</label><p className="mt-1 text-xs text-[#4a4a4f]">Choose 15–90 minutes.</p><div className="mt-4 flex items-center gap-2"><button aria-label="Decrease interval by five minutes" type="button" onClick={()=>change(value-5)} className="grid h-11 w-11 place-items-center rounded-xl border border-[#ececee] text-xl font-black focus-visible:outline focus-visible:outline-2 focus-visible:outline-offset-2">−</button><div className="relative flex min-h-11 flex-1 items-center rounded-xl bg-[#f4f5f6] px-3"><input id="interval" value={value} onChange={e=>change(Number(e.target.value)||15)} onKeyDown={e=>{if(e.key==="ArrowUp")change(value+5);if(e.key==="ArrowDown")change(value-5);if(e.key==="Home")change(15);if(e.key==="End")change(90)}} className="w-full bg-transparent text-center text-lg font-black outline-none" inputMode="numeric"/><motion.span animate={reduced?{}:{y:[0,-2,0],opacity:[1,.7,1]}} transition={{duration:.15}} className="rounded-lg bg-[#f5e642] px-2 py-1 text-xs font-bold">min</motion.span></div><button aria-label="Increase interval by five minutes" type="button" onClick={()=>change(value+5)} className="grid h-11 w-11 place-items-center rounded-xl bg-[#111] text-xl font-black text-white focus-visible:outline focus-visible:outline-2 focus-visible:outline-offset-2">+</button></div><p aria-live="polite" className="mt-3 text-xs text-[#4a4a4f]">Interval set to {value} minutes.</p></section>}
